async (page) => {
  await page.evaluate(() => { window.__wsMessages = []; });
  // Talk 6 times to cycle through dialogue
  for (let i = 0; i < 6; i++) {
    await page.evaluate((id) => window.__talkToNPC(id), '1-5339474');
    await page.waitForTimeout(800);
  }
  const msgs = await page.evaluate(() => JSON.stringify(window.__wsMessages));
  // Parse and show incoming messages
  const parsed = JSON.parse(msgs);
  const incoming = parsed.filter(m => m.dir === 'in').map(m => m.data.substring(0, 200));
  return JSON.stringify(incoming, null, 2);
}
